def get_vendor(mac):
    if not mac:
        return ""
    prefix = mac.upper().replace("-", ":")[:8]
    return OUI_VENDOR.get(prefix, "")


def infer_device_type(ip="", vendor="", hostname=""):
    """结合 IP 特征 + 厂商名推断设备类型"""
    if ip.endswith(".1") or ip.endswith(".254"):
        return "路由器/网关"
    v = vendor.lower()
    h = hostname.lower()
    if "cisco" in v or "h3c" in v or "ruijie" in v:
        return "交换机/路由器"
    if "huawei" in v and ("s" in ip.split(".")[-1] or ip.endswith(".1")):
        return "交换机/路由器"
    if "tp-link" in v or "tenda" in v or "netgear" in v or "mercusys" in v:
        return "路由器/AP"
    if "d-link" in v or "zyxel" in v or "mikrotik" in v or "ubiquiti" in v:
        return "路由器/AP"
    if "apple" in v:
        return "苹果设备"
    if "samsung" in v or "xiaomi" in v or "zte" in v:
        return "手机/平板"
    if "intel" in v or "amd" in v or "nvidia" in v:
        return "PC/服务器"
    if "dell" in v or "hp" in v or "lenovo" in v or "acer" in v:
        return "PC/服务器"
    if "vmware" in v or "virtualbox" in v or "parallels" in v or "xensource" in v:
        return "虚拟机"
    if "synology" in v or "qnap" in v:
        return "NAS/存储"
    if "hikvision" in v or "dahua" in v:
        return "摄像头"
    if "canon" in v or "brother" in v or "epson" in v or "hp" in h:
        return "打印机"
    if any(k in h for k in ["router","gateway","tplink","netgear"]):
        return "路由器/网关"
    if any(k in h for k in ["server","nas","synology","qnap"]):
        return "服务器/NAS"
    if any(k in h for k in ["printer","print","canon","brother","epson"]):
        return "打印机"
    if any(k in h for k in ["switch","sw"]):
        return "交换机"
    return "未知设备"


