# ── 网络诊断（Traceroute / Nslookup / ARP 冲突）──────────────────

def _show_network_diag():
    """网络诊断窗口：Traceroute、Nslookup、ARP 冲突检测"""
    import tkinter as tk
    from tkinter import ttk, scrolledtext
    import queue

    win = tk.Toplevel(_tk_root)
    win.title("网络诊断 - lanwatch")
    win.geometry("780x540")
    win.resizable(True, True)
    sw = win.winfo_screenwidth(); sh = win.winfo_screenheight()
    win.geometry(f"+{(sw-780)//2}+{(sh-540)//2}")

    trace_q = queue.Queue()
    nslookup_q = queue.Queue()
    arp_q = queue.Queue()
    _running = [False]
    _poll_active = [True]
    _ENC = "gbk"

    def _poll_queue(txt, q):
        while True:
            try:
                line = q.get_nowait()
                txt.insert("end", line)
                txt.see("end")
            except queue.Empty:
                break
        if _poll_active[0]:
            win.after(100, lambda: _poll_queue(txt, q))

    # ── Notebook ──────────────────────────────────────────────
    nb = ttk.Notebook(win)
    nb.pack(fill="both", expand=True, padx=8, pady=(8, 0))

    # ══════════════════════════════════════════════════════════
    # TAB 1: Traceroute / Pathping
    # ══════════════════════════════════════════════════════════
    f1 = tk.Frame(nb, bg=C_BG)
    nb.add(f1, text=" Traceroute ")

    row1 = tk.Frame(f1, bg=C_BG)
    row1.pack(fill="x", padx=8, pady=(8, 4))
    tk.Label(row1, text="目标地址:", font=("微软雅黑", 9), bg=C_BG,
             fg=C_TEXT).pack(side="left")
    ent_target = tk.Entry(row1, font=("微软雅黑", 9), bg=C_INPUT_BG,
                          relief="flat", highlightthickness=1,
                          highlightcolor=C_BORDER, highlightbackground=C_BORDER)
    ent_target.pack(side="left", fill="x", expand=True, padx=(4, 8))
    ent_target.insert(0, "baidu.com")

    _trace_type = tk.StringVar(value="tracert")
    tk.Radiobutton(row1, text="tracert", variable=_trace_type, value="tracert",
                   font=("微软雅黑", 9), bg=C_BG, fg=C_TEXT,
                   selectcolor=C_BG, activebackground=C_BG).pack(side="left")
    tk.Radiobutton(row1, text="pathping", variable=_trace_type, value="pathping",
                   font=("微软雅黑", 9), bg=C_BG, fg=C_TEXT,
                   selectcolor=C_BG, activebackground=C_BG).pack(side="left", padx=(4, 8))

    def _run_trace():
        if _running[0]:
            return
        target = ent_target.get().strip()
        if not target:
            return
        _running[0] = True
        btn_trace.config(state="disabled", text="运行中...")
        txt_trace.delete("1.0", "end")
        mode = _trace_type.get()
        cmd = [mode, target] if mode == "tracert" else ["pathping", "-n", "-q", "10", "-w", "500", target]

        def _stream():
            try:
                startup = subprocess.STARTUPINFO()
                startup.dwFlags |= subprocess.STARTF_USESHOWWINDOW
                startup.wShowWindow = subprocess.SW_HIDE
                proc = subprocess.Popen(cmd, stdout=subprocess.PIPE,
                                        stderr=subprocess.STDOUT,
                                        encoding=_ENC, errors="replace",
                                        startupinfo=startup, shell=False)
                for line in iter(proc.stdout.readline, ""):
                    trace_q.put(line)
                proc.wait()
            except Exception as e:
                trace_q.put(f"[错误] {e}\n")
            finally:
                _running[0] = False
                win.after(0, lambda: btn_trace.config(state="normal", text="执行"))

        threading.Thread(target=_stream, daemon=True).start()

    def _stop_trace():
        _running[0] = False
        btn_trace.config(state="normal", text="执行")

    btn_frame1 = tk.Frame(f1, bg=C_BG)
    btn_frame1.pack(fill="x", padx=8, pady=(0, 4))
    btn_trace = tk.Button(btn_frame1, text="执行", command=_run_trace,
                          font=("微软雅黑", 9), bg=C_ACCENT, fg="white",
                          relief="flat", padx=12, pady=2)
    btn_trace.pack(side="left")
    tk.Button(btn_frame1, text="停止", command=_stop_trace,
              font=("微软雅黑", 9), bg=C_BTN_SEC, fg=C_TEXT,
              relief="flat", padx=12, pady=2).pack(side="left", padx=(4, 0))
    tk.Button(btn_frame1, text="清空", command=lambda: txt_trace.delete("1.0", "end"),
              font=("微软雅黑", 9), bg=C_BTN_SEC, fg=C_TEXT,
              relief="flat", padx=12, pady=2).pack(side="left", padx=(4, 0))

    txt_trace = scrolledtext.ScrolledText(f1, font=("Consolas", 9), bg="#1E1E1E",
                                          fg="#D4D4D4", insertbackground="white",
                                          relief="flat", highlightthickness=1,
                                          highlightcolor=C_BORDER)
    txt_trace.pack(fill="both", expand=True, padx=8, pady=(0, 8))

    # ══════════════════════════════════════════════════════════
    # TAB 2: Nslookup
    # ══════════════════════════════════════════════════════════
    f2 = tk.Frame(nb, bg=C_BG)
    nb.add(f2, text=" Nslookup ")

    row2 = tk.Frame(f2, bg=C_BG)
    row2.pack(fill="x", padx=8, pady=(8, 4))
    tk.Label(row2, text="域名:", font=("微软雅黑", 9), bg=C_BG,
             fg=C_TEXT).pack(side="left")
    ent_domain = tk.Entry(row2, font=("微软雅黑", 9), bg=C_INPUT_BG,
                          relief="flat", highlightthickness=1,
                          highlightcolor=C_BORDER, highlightbackground=C_BORDER)
    ent_domain.pack(side="left", fill="x", expand=True, padx=(4, 0))
    ent_domain.insert(0, "baidu.com")

    def _run_nslookup():
        if _running[0]:
            return
        domain = ent_domain.get().strip()
        if not domain:
            return
        _running[0] = True
        btn_nslookup.config(state="disabled", text="运行中...")
        txt_nslookup.delete("1.0", "end")
        nslookup_q.queue.clear()

        def _do():
            times = []
            for i in range(3):
                if not _running[0]:
                    break
                try:
                    startup = subprocess.STARTUPINFO()
                    startup.dwFlags |= subprocess.STARTF_USESHOWWINDOW
                    startup.wShowWindow = subprocess.SW_HIDE
                    t0 = time.time()
                    r = subprocess.run(["nslookup", domain],
                                       capture_output=True, timeout=10,
                                       encoding=_ENC, errors="replace",
                                       startupinfo=startup)
                    elapsed = (time.time() - t0) * 1000
                    times.append(elapsed)
                    nslookup_q.put(f"─── 第 {i+1} 次 ─── ({elapsed:.0f}ms)\n{r.stdout.strip()}\n\n")
                    if r.stderr and r.stderr.strip():
                        nslookup_q.put(f"[stderr]\n{r.stderr.strip()}\n\n")
                except subprocess.TimeoutExpired:
                    nslookup_q.put(f"─── 第 {i+1} 次 ─── 超时\n\n")
                except Exception as e:
                    nslookup_q.put(f"─── 第 {i+1} 次 ─── 错误: {e}\n\n")
            if times:
                avg = sum(times) / len(times)
                nslookup_q.put(f"═══ 平均响应时间: {avg:.0f}ms ({len(times)}/3 次成功) ═══\n")
            else:
                nslookup_q.put("═══ nslookup 未获取到有效结果 ═══\n")
            _running[0] = False
            win.after(0, lambda: btn_nslookup.config(state="normal", text="执行"))

        threading.Thread(target=_do, daemon=True).start()

    def _stop_nslookup():
        _running[0] = False
        btn_nslookup.config(state="normal", text="执行")

    btn_frame2 = tk.Frame(f2, bg=C_BG)
    btn_frame2.pack(fill="x", padx=8, pady=(0, 4))
    btn_nslookup = tk.Button(btn_frame2, text="执行", command=_run_nslookup,
                             font=("微软雅黑", 9), bg=C_ACCENT, fg="white",
                             relief="flat", padx=12, pady=2)
    btn_nslookup.pack(side="left")
    tk.Button(btn_frame2, text="停止", command=_stop_nslookup,
              font=("微软雅黑", 9), bg=C_BTN_SEC, fg=C_TEXT,
              relief="flat", padx=12, pady=2).pack(side="left", padx=(4, 0))
    tk.Button(btn_frame2, text="清空", command=lambda: txt_nslookup.delete("1.0", "end"),
              font=("微软雅黑", 9), bg=C_BTN_SEC, fg=C_TEXT,
              relief="flat", padx=12, pady=2).pack(side="left", padx=(4, 0))

    txt_nslookup = scrolledtext.ScrolledText(f2, font=("Consolas", 9), bg="#1E1E1E",
                                             fg="#D4D4D4", insertbackground="white",
                                             relief="flat", highlightthickness=1,
                                             highlightcolor=C_BORDER)
    txt_nslookup.pack(fill="both", expand=True, padx=8, pady=(0, 8))

    # ══════════════════════════════════════════════════════════
    # TAB 3: ARP 冲突检测
    # ══════════════════════════════════════════════════════════
    f3 = tk.Frame(nb, bg=C_BG)
    nb.add(f3, text=" ARP 冲突检测 ")

    def _scan_arp_conflicts():
        if _running[0]:
            return
        _running[0] = True
        btn_arp.config(state="disabled", text="扫描中...")
        txt_arp.delete("1.0", "end")
        arp_q.queue.clear()
        txt_arp.insert("end", "正在读取 ARP 表...\n")

        def _do_arp():
            try:
                startup = subprocess.STARTUPINFO()
                startup.dwFlags |= subprocess.STARTF_USESHOWWINDOW
                startup.wShowWindow = subprocess.SW_HIDE
                r = subprocess.run(["arp", "-a"], capture_output=True, timeout=5,
                                   encoding=_ENC, errors="replace", startupinfo=startup)
                output = r.stdout
            except subprocess.TimeoutExpired:
                arp_q.put("[错误] arp -a 命令超时（>5秒），请检查网络适配器状态\n")
                _running[0] = False
                win.after(0, lambda: btn_arp.config(state="normal", text="扫描 ARP 冲突"))
                return
            except Exception as e:
                arp_q.put(f"[错误] 读取 ARP 表失败: {e}\n")
                _running[0] = False
                win.after(0, lambda: btn_arp.config(state="normal", text="扫描 ARP 冲突"))
                return

            ip_to_macs = {}
            for line in output.splitlines():
                line_norm = line.replace("-", ":")
                m = re.search(r"(\d+\.\d+\.\d+\.\d+)\s+([0-9a-fA-F:]{17})", line_norm)
                if m:
                    ip = m.group(1)
                    mac = m.group(2).upper()
                    ip_to_macs.setdefault(ip, set()).add(mac)

            conflicts = [(ip, macs) for ip, macs in ip_to_macs.items() if len(macs) > 1]
            total_entries = len(ip_to_macs)

            arp_q.put(f"ARP 表条目数: {total_entries}\n")
            if conflicts:
                arp_q.put(f"\n⚠ 发现 {len(conflicts)} 个冲突 IP:\n\n")
                for ip, macs in conflicts:
                    arp_q.put(f"  {ip}\n")
                    for m in macs:
                        arp_q.put(f"    └─ MAC: {m}\n")
                    arp_q.put("\n")
            else:
                arp_q.put("\n✅ 未发现 ARP 冲突（所有 IP 均对应唯一 MAC）\n")

            # 厂商识别
            arp_q.put("\n── 设备厂商识别 ──\n")
            seen_ouis = set()
            for ip, macs in ip_to_macs.items():
                for mac in macs:
                    vendor = get_vendor(mac)
                    if vendor:
                        arp_q.put(f"  {mac[:8]} → {vendor}  ({mac})\n")
                    else:
                        arp_q.put(f"  {mac[:8]} → 未知厂商  ({mac})\n")
            _running[0] = False
            win.after(0, lambda: btn_arp.config(state="normal", text="扫描 ARP 冲突"))

        threading.Thread(target=_do_arp, daemon=True).start()

    btn_frame3 = tk.Frame(f3, bg=C_BG)
    btn_frame3.pack(fill="x", padx=8, pady=(8, 4))
    btn_arp = tk.Button(btn_frame3, text="扫描 ARP 冲突", command=_scan_arp_conflicts,
                        font=("微软雅黑", 9), bg=C_ACCENT, fg="white",
                        relief="flat", padx=12, pady=2)
    btn_arp.pack(side="left")
    tk.Button(btn_frame3, text="清空", command=lambda: txt_arp.delete("1.0", "end"),
              font=("微软雅黑", 9), bg=C_BTN_SEC, fg=C_TEXT,
              relief="flat", padx=12, pady=2).pack(side="left", padx=(4, 0))

    txt_arp = scrolledtext.ScrolledText(f3, font=("Consolas", 9), bg="#1E1E1E",
                                        fg="#D4D4D4", insertbackground="white",
                                        relief="flat", highlightthickness=1,
                                        highlightcolor=C_BORDER)
    txt_arp.pack(fill="both", expand=True, padx=8, pady=(0, 8))

    # ── 底部状态条 ──
    status_bar = tk.Frame(win, bg=C_BORDER)
    status_bar.pack(fill="x", padx=8, pady=(4, 8))

    def _copy_all():
        text = ""
        for t in (txt_trace, txt_nslookup, txt_arp):
            try:
                text += t.get("1.0", "end") + "\n"
            except Exception:
                pass
        win.clipboard_clear()
        win.clipboard_append(text)

    tk.Button(status_bar, text="复制全部", command=_copy_all,
              font=("微软雅黑", 9), bg=C_BTN_SEC, fg=C_TEXT,
              relief="flat", padx=8, pady=1).pack(side="left")
    lbl_status = tk.Label(status_bar, text="就绪", font=("微软雅黑", 9),
                          bg=C_BORDER, fg=C_MUTED)
    lbl_status.pack(side="right")

    # 启动队列轮询（每 tab 独立队列）
    _poll_active[0] = True
    win.after(200, lambda: _poll_queue(txt_trace, trace_q))
    win.after(200, lambda: _poll_queue(txt_nslookup, nslookup_q))
    win.after(200, lambda: _poll_queue(txt_arp, arp_q))

    def _on_close():
        _poll_active[0] = False
        _running[0] = False
        win.destroy()

    win.protocol("WM_DELETE_WINDOW", _on_close)


def _show_network_events():
    """故障记录窗口"""
    try:
        import tkinter as tk
        from tkinter import ttk, messagebox
        import csv

        win = tk.Toplevel(_tk_root)
        win.title("故障记录 - lanwatch")
        win.geometry("820x480")
        win.resizable(True, True)
        win.update_idletasks()
        sw = win.winfo_screenwidth(); sh = win.winfo_screenheight()
        ww, wh = 820, 480
        win.geometry(f"+{(sw-ww)//2}+{(sh-wh)//2}")

        # ── 工具栏 ──
        toolbar = tk.Frame(win, bg=C_BG)
        toolbar.pack(fill="x", padx=8, pady=(8, 0))

        total_label = tk.Label(toolbar, text="加载中...", font=("微软雅黑", 9),
                               bg=C_BG, fg=C_MUTED)
        total_label.pack(side="left")

        def export_csv():
            from network_monitor import query_events
            events = query_events(limit=9999)
            if not events:
                messagebox.showinfo("导出", "没有数据可导出", parent=win)
                return
            from tkinter import filedialog
            path = filedialog.asksaveasfilename(
                defaultextension=".csv",
                filetypes=[("CSV", "*.csv")],
                title="导出故障记录",
                parent=win
            )
            if not path:
                return
            try:
                with open(path, "w", newline="", encoding="utf-8-sig") as f:
                    w = csv.writer(f)
                    w.writerow(["ID", "类型", "开始时间", "结束时间", "持续秒数",
                                "网关", "目标", "错误信息", "故障跳数", "创建时间"])
                    for e in events:
                        w.writerow([
                            e["id"], e["event_type"], e["start_time"], e["end_time"],
                            e["duration_seconds"], e["gateway"], e["target"],
                            e["error_message"], e["hop_count"], e["created_at"]
                        ])
                messagebox.showinfo("导出", "已导出: " + path, parent=win)
            except Exception as e:
                messagebox.showerror("导出失败", str(e), parent=win)

        tk.Button(toolbar, text="导出 CSV", command=export_csv,
                  font=("微软雅黑", 9), bg=C_BTN_SEC, fg=C_TEXT,
                  relief="flat", padx=12, pady=2).pack(side="right")

        # ── 表格 ──
        frame = tk.Frame(win, bg=C_BG)
        frame.pack(fill="both", expand=True, padx=8, pady=8)

        columns = ("id", "event_type", "start_time", "duration", "hop_count", "diag_conclusion", "error_message")
        headings = ["ID", "类型", "时间", "持续时长", "故障点", "诊断结论", "错误原因"]
        col_widths = [40, 90, 160, 80, 70, 180, 120]

        tree = ttk.Treeview(frame, columns=columns, show="headings", height=16)
        for col, hd, w in zip(columns, headings, col_widths):
            tree.heading(col, text=hd)
            tree.column(col, width=w, minwidth=w // 2)

        scroll_y = ttk.Scrollbar(frame, orient="vertical", command=tree.yview)
        tree.configure(yscrollcommand=scroll_y.set)
        scroll_y.pack(side="right", fill="y")
        tree.pack(fill="both", expand=True)

        # ── 加载数据 ──
        def refresh():
            from network_monitor import query_events, count_events
            for row in tree.get_children():
                tree.delete(row)
            events = query_events(limit=200)
            total_label.config(text="共 %d 条记录" % count_events())
            for e in events:
                ev_type = e.get("event_type", "")
                if ev_type == "offline":
                    type_label = "断线"
                elif ev_type == "online":
                    type_label = "恢复"
                elif ev_type == "quality_degraded":
                    type_label = "质量劣化"
                else:
                    type_label = ev_type

                dur = e.get("duration_seconds")
                dur_str = ("%d 秒" % dur) if dur else "进行中"

                hop = e.get("hop_count", 0)
                hop_label = {0: "本机", 1: "网关", 2: "上游路由", 3: "公网"}.get(hop, "未知")

                diag_concl = e.get("diag_conclusion") or ""
                tree.insert("", "end", values=(
                    e["id"], type_label, e.get("start_time", ""),
                    dur_str, hop_label, diag_concl, e.get("error_message", "")
                ))
            # 定时刷新
            if win.winfo_exists():
                win.after(5000, refresh)

        refresh()

        # ── 双击详情 ──
        def show_detail(event):
            sel = tree.selection()
            if not sel:
                return
            vals = tree.item(sel[0], "values")
            if not vals:
                return
            eid = vals[0]
            from network_monitor import get_db
            conn = get_db()
            try:
                row = conn.execute(
                    "SELECT * FROM network_events WHERE id = ?", (eid,)
                ).fetchone()
            finally:
                conn.close()
            if not row:
                return
            r = dict(row)
            diag = r.get("diag_conclusion") or ""
            dns = r.get("diag_nslookup") or ""
            trace = r.get("diag_traceroute") or ""
            recov = r.get("recovery_diag") or ""
            root = r.get("root_cause_hint") or ""
            detail = (
                "事件详情\n"
                + "=" * 30 + "\n"
                + "ID: %s\n" % r["id"]
                + "类型: %s\n" % r["event_type"]
                + "开始: %s\n" % r["start_time"]
                + "结束: %s\n" % (r["end_time"] or "进行中")
                + "持续: %s\n" % ("%d 秒" % r["duration_seconds"] if r["duration_seconds"] else "进行中")
                + "网关: %s\n" % (r["gateway"] or "-")
                + "目标: %s\n" % (r["target"] or "-")
                + "故障跳数: %d\n" % r["hop_count"]
                + "错误: %s\n" % (r["error_message"] or "-")
                + "诊断结论: %s\n" % (diag or "（未诊断）")
                + "根因提示: %s\n" % (root or "（无）")
                + "\n"
            )
            if dns:
                detail += "── nslookup ──\n%s\n\n" % dns[:600]
            if trace:
                detail += "── traceroute ──\n%s\n\n" % trace[:800]
            if recov:
                detail += "── 恢复后 traceroute ──\n%s\n" % recov[:800]
            from tkinter import scrolledtext
            dlg = tk.Toplevel(win)
            dlg.title("故障详情 #%s" % r["id"])
            dlg.geometry("600x500")
            dlg.resizable(True, True)
            txt = scrolledtext.ScrolledText(dlg, font=("Consolas", 9),
                                            wrap="word")
            txt.pack(fill="both", expand=True, padx=8, pady=8)
            txt.insert("1.0", detail)
            txt.config(state="disabled")

        tree.bind("<Double-1>", show_detail)

        win.protocol("WM_DELETE_WINDOW", win.destroy)
    except Exception:
        pass
